const { ApolloServer, gql } = require('apollo-server');
const { Sequelize, DataTypes } = require('sequelize');
const jwt = require('jsonwebtoken');
const express = require('express');

// Initialize Sequelize
const sequelize = new Sequelize('sqlite::memory:');

// Define models
const User = sequelize.define('User', {
  username: {
    type: DataTypes.STRING,
    allowNull: false,
    unique: true,
  },
  password: {
    type: DataTypes.STRING,
    allowNull: false,
  },
});

const Post = sequelize.define('Post', {
  title: {
    type: DataTypes.STRING,
    allowNull: false,
  },
  content: {
    type: DataTypes.TEXT,
    allowNull: false,
  },
});

const Comment = sequelize.define('Comment', {
  content: {
    type: DataTypes.TEXT,
    allowNull: false,
  },
});

// Define relationships
User.hasMany(Post);
Post.belongsTo(User);
Post.hasMany(Comment);
Comment.belongsTo(Post);
User.hasMany(Comment);
Comment.belongsTo(User);

// GraphQL schema
const typeDefs = gql`
  type User {
    id: ID!
    username: String!
    posts: [Post]
    comments: [Comment]
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    user: User
    comments: [Comment]
  }

  type Comment {
    id: ID!
    content: String!
    user: User
    post: Post
  }

  type Query {
    users: [User]
    posts: [Post]
    comments: [Comment]
  }

  type Mutation {
    createUser(username: String!, password: String!): User
    createPost(title: String!, content: String!): Post
    createComment(postId: ID!, content: String!): Comment
  }
`;

// Resolvers
const resolvers = {
  Query: {
    users: () => User.findAll(),
    posts: () => Post.findAll(),
    comments: () => Comment.findAll(),
  },
  Mutation: {
    createUser: async (_, { username, password }) => {
      const user = await User.create({ username, password });
      return user;
    },
    createPost: async (_, { title, content }, context) => {
      if (!context.user) throw new Error('Unauthorized');
      const post = await Post.create({ title, content, userId: context.user.id });
      return post;
    },
    createComment: async (_, { postId, content }, context) => {
      if (!context.user) throw new Error('Unauthorized');
      const comment = await Comment.create({ content, postId, userId: context.user.id });
      return comment;
    },
  },
  User: {
    posts: (user) => Post.findAll({ where: { userId: user.id } }),
    comments: (user) => Comment.findAll({ where: { userId: user.id } }),
  },
  Post: {
    user: (post) => User.findByPk(post.userId),
    comments: (post) => Comment.findAll({ where: { postId: post.id } }),
  },
  Comment: {
    user: (comment) => User.findByPk(comment.userId),
    post: (comment) => Post.findByPk(comment.postId),
  },
};

// Authentication middleware
const getUser = (token) => {
  if (token) {
    try {
      return jwt.verify(token, 'your_secret_key');
    } catch (err) {
      throw new Error('Invalid token');
    }
  }
  return null;
};

// Apollo Server setup
const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    const token = req.headers.authorization || '';
    const user = getUser(token.replace('Bearer ', ''));
    return { user };
  },
});

// Start server
sequelize.sync().then(() => {
  server.listen().then(({ url }) => {
    console.log(`🚀 Server ready at ${url}`);
  });
});